### Intercept Booking with Booker Atom (React)

Source: https://github.com/calcom/cal.com/blob/main/docs/platform/guides/custom-booking-flow.mdx

Demonstrates how to create an `interceptBooking` function to capture booking data when a user clicks 'Book'. This function is passed to the `handleCreateBooking` prop of the Booker atom. The intercepted data can then be used for custom actions before creating the booking via an API call.

```javascript
import { Booker, UseCreateBookingInput } from "@calcom/atoms";
import { useCallback } from "react";


export function BookingPage(props: { calUsername: string; calEmail: string }) {
    ...
    const interceptBooking = useCallback((data: UseCreateBookingInput) => {
        console.log(data);
        // Your custom logic here
        // e.g., process payment, show a confirmation modal
        // Then, make a POST request to the create booking endpoint
    }, []);

  return (
    <Booker
        handleCreateBooking={interceptBooking}
        ...
    />
  );
}
```

